// ─── Constants ────────────────────────────────────────────────────────────────
const DRAW_DURATION = 2.5;
const BG_CLR = '#2A1A12';

function preloadImages(urls: string[], onOneLoaded?: () => void): Promise<void> {
  if (urls.length === 0) return Promise.resolve();
  return Promise.all(
    urls.map(
      (src) =>
        new Promise<void>((resolve) => {
          const img = new Image();
          img.onload = () => {
            onOneLoaded?.();
            resolve();
          };
          img.onerror = () => {
            onOneLoaded?.();
            resolve();
          };
          img.src = src;
        })
    )
  ).then(() => {});
}

export interface LoadingScreenProps {
  onComplete: () => void;
  /** Image URLs to preload in the background while the splash is shown. Progress bar reflects load progress. */
  assetsToPreload?: string[];
}

export const LoadingScreen: React.FC<LoadingScreenProps> = ({ onComplete, assetsToPreload = [] }) => {
  const [progress, setProgress] = useState(0);
  const [loadedCount, setLoadedCount] = useState(0);
  const totalCount = assetsToPreload.length || 1;
  const allLoadedRef = useRef(false);
  const completedRef = useRef(false);

  useEffect(() => {
    if (assetsToPreload.length === 0) {
      const interval = setInterval(() => {
        setProgress((prev) => {
          if (prev >= 100) {
            clearInterval(interval);
            setTimeout(onComplete, 300);
            return 100;
          }
          return prev + 2;
        });
      }, 30);
      return () => clearInterval(interval);
    }

    const start = Date.now();
    let cancelled = false;

    preloadImages(assetsToPreload, () => {
      if (cancelled) return;
      setLoadedCount((n) => Math.min(n + 1, totalCount));
    }).then(() => {
      if (cancelled) return;
      allLoadedRef.current = true;
      setLoadedCount(totalCount);
    });

    const interval = setInterval(() => {
      if (cancelled || completedRef.current) return;
      const elapsed = Date.now() - start;
      // Do NOT wait for images to finish loading: keep the splash running
      // for the animation duration, while preloading continues in the background.
      if (elapsed >= MIN_DISPLAY_MS) {
        completedRef.current = true;
        clearInterval(interval);
        setProgress(100);
        setTimeout(onComplete, 300);
      }
    }, 80);

    return () => {
      cancelled = true;
      clearInterval(interval);
    };
  }, [assetsToPreload, onComplete, totalCount]);

  useEffect(() => {
    if (assetsToPreload.length === 0) return;
    const pct = totalCount ? Math.round((loadedCount / totalCount) * 100) : 0;
    setProgress((prev) => Math.max(prev, Math.min(pct, 98)));
  }, [loadedCount, totalCount, assetsToPreload.length]);

  return (
    <motion.div
      className="fixed top-0 left-0 w-screen h-screen z-50 bg-[#2A1A12] flex flex-col items-center justify-center gap-8 px-6 relative"
      exit={{ opacity: 0 }}
      transition={{ duration: 0.4 }}
      style={{ backgroundColor: BG_CLR }}
    >
      {/* Subtle radial glow behind logo */}
      <div
        className="pointer-events-none absolute inset-0"
        style={{
          background:
            'radial-gradient(ellipse 55% 40% at 50% 46%, rgba(212,165,116,0.07) 0%, transparent 70%)',
        }}
      />

      <motion.div
        initial={{ opacity: 0, y: 12 }}
        animate={{ opacity: 1, y: 0 }}
        transition={{ duration: 0.6, ease: 'easeOut' }}
        className="w-56 sm:w-64 md:w-80 max-h-[38vh]"
      >
        <svg
          viewBox="3150 230 1730 1380"
          xmlns="http://www.w3.org/2000/svg"
          className="w-full h-auto"
          aria-label="Farfalle Coffee logo"
        >
          {PATHS.map(({ d, sw }, i) => (
            <motion.path
              key={i}
              d={d}
              stroke="#D4A574"
              strokeWidth={sw}
              strokeLinecap="round"
              strokeLinejoin="round"
              initial={{
                pathLength: 0,
                fill: 'rgba(212, 165, 116, 0)', // Transparent Gold
                opacity: 1,
              }}
              animate={{
                pathLength: 1,
                fill: 'rgba(212, 165, 116, 1)', // Solid Gold
              }}
              transition={{
                pathLength: {
                  duration: DRAW_DURATION,
                  ease: 'easeInOut',
                  delay: i * 0.1,
                },
                fill: {
                  duration: 0.8,
                  ease: 'easeIn',
                  delay: DRAW_DURATION,
                },
              }}
            />
          ))}
        </svg>
      </motion.div>

      <motion.h1
        className="text-3xl md:text-4xl font-normal select-none text-[#F5E6D3]"
        style={{ fontFamily: "'Playfair Display', serif", letterSpacing: '0px' }}
        initial={{ opacity: 0, y: 8 }}
        animate={{ opacity: 1, y: 0 }}
        transition={{ duration: 0.7, ease: 'easeOut', delay: 0.3 }}
      >
        Farfalle{' '}
        <em
          className="font-normal not-italic"
          style={{
            color: '#D4A574',
            letterSpacing: '0.22em',
            fontStyle: 'normal',
            textTransform: 'uppercase',
          }}
        >
          COFFEE
        </em>
      </motion.h1>

      {/* Progress bar */}
      <motion.div
        initial={{ opacity: 0 }}
        animate={{ opacity: 1 }}
        transition={{ duration: 0.5, delay: 0.5 }}
        className="flex flex-col items-center gap-3"
      >
        <div
          className="relative w-52 sm:w-64 h-px overflow-hidden"
          style={{ backgroundColor: 'rgba(212,165,116,0.18)' }}
        >
          {/* Fill bar tied to actual preload progress */}
          <motion.div
            className="absolute left-0 top-0 h-full"
            style={{ backgroundColor: '#D4A574', width: '100%' }}
            initial={{ scaleX: 0, originX: 0 }}
            animate={{ scaleX: Math.max(0, Math.min(1, progress / 100)) }}
            transition={{ duration: 0.12, ease: 'easeOut' }}
          />

          {/* Shimmer highlight (decorative) */}
          <motion.div
            className="absolute top-0 h-full w-10"
            style={{
              background: 'linear-gradient(90deg, transparent, rgba(255,255,255,0.55), transparent)',
            }}
            initial={{ left: '-2rem' }}
            animate={{ left: '100%' }}
            transition={{
              duration: DRAW_DURATION,
              ease: 'easeInOut',
              delay: 0.1,
            }}
          />
        </div>

        <motion.p
          className="text-xs tracking-widest uppercase select-none text-[#D4A574]"
          style={{ color: 'rgba(212,165,116,0.55)', letterSpacing: '0.28em' }}
          initial={{ opacity: 0 }}
          animate={{ opacity: [0, 0.6, 0.4, 0.7, 0.5, 0.8] }}
          transition={{
            duration: DRAW_DURATION,
            delay: 0.5,
            times: [0, 0.2, 0.4, 0.6, 0.8, 1],
          }}
        >
          Brewing your experience…
        </motion.p>
      </motion.div>
    </motion.div>
  );
};
